MVNO_PATTERNS = ["mvno", "mobile virtual", "cricket", "metro by t-mobile", "visible", "mint mobile", "boost mobile", "ting", "tracfone", "straight talk", "google fi", "republic wireless"]

async def _resolve_target(target: str) -> tuple:
    if is_ip(target):
        return target, True
    ip = resolve_ip(target)
    if ip:
        return ip, False
    return None, "DNS resolution failed"

async def _check_mobile_operator(ip: str, client) -> list:
    findings = []
    data = await safe_fetch_json(client, f"https://ipinfo.io/{ip}/json",
        headers={"User-Agent": "Mozilla/5.0"})
    if data:
        org = data.get("org", "").lower()
        asn_raw = data.get("asn", "")
        asn_num = 0
        if asn_raw:
            try:
                asn_num = int(asn_raw.replace("AS", ""))
            except ValueError:
                pass

        for name, info in MOBILE_OPERATORS.items():
            matched = False
            if info["asns"] and asn_num in info["asns"]:
                matched = True
            if not matched:
                for pat in info["org_patterns"]:
                    if pat in org:
                        matched = True
                        break
            if matched:
                findings.append(make_finding(
                    entity=f"{name} ({info['country']})",
                    ftype=f"Mobile Network Operator ({info['type']})",
                    source="MobileNetworkScanner",
                    confidence="High",
                    color="purple",
                    category="Geo / Network OSINT",
                    threat_level="Informational",
                    status="Detected",
                    resolution=ip,
                    raw_data=f"Mobile operator: {name}. Country: {info['country']}. Type: {info['type']}.",
                    tags=["mobile", "mno", name.lower().replace(" ", "-")]
                ))
                findings.append(make_finding(
                    entity=f"{name} - Backhaul Analysis Possible",
                    ftype="Mobile Backhaul",
                    source="MobileNetworkScanner",
                    confidence="Medium",
                    color="slate",
                    category="Geo / Network OSINT",
                    threat_level="Informational",
                    status="Linked",
                    resolution=ip,
                    raw_data=f"Operator {name} likely uses {info['type']} backhaul infrastructure",
                    tags=["mobile", "backhaul", name.lower().replace(" ", "-")]
                ))
                break

        for mvno_pat in MVNO_PATTERNS:
            if mvno_pat in org:
                findings.append(make_finding(
                    entity=f"MVNO: {org[:80]}",
                    ftype="MVNO (Mobile Virtual Network Operator)",
                    source="MobileNetworkScanner",
                    confidence="High",
                    color="blue",
                    category="Geo / Network OSINT",
                    threat_level="Informational",
                    status="Detected",
                    resolution=ip,
                    raw_data=f"MVNO operator detected: {org}",
                    tags=["mobile", "mvno"]
                ))
                break

        if "5g" in org or "5G" in org:
            findings.append(make_finding(
                entity="5G Network Capability",
                ftype="Mobile Generation",
                source="MobileNetworkScanner",
                confidence="Medium",
                color="blue",
                category="Geo / Network OSINT",
                threat_level="Informational",
                status="Detected",
                resolution=ip,
                raw_data=f"5G capability detected in operator {org[:80]}",
                tags=["mobile", "5g"]
            ))

    return findings

