    findings = []
    target = target.strip().lower()
    if target.startswith("http"):
        from urllib.parse import urlparse
        target = urlparse(target).netloc

    ip, is_ip_flag = await _resolve_target(target)
    if ip is None:
        findings.append(make_finding(entity=f"DNS resolution failed: {target}", ftype="DNS Error", source="MobileNetworkScanner", confidence="Low", color="red", category="Geo / Network OSINT", raw_data=str(is_ip_flag)[:200], tags=["error"]))
        return findings

    if not is_ip_flag:
        findings.append(make_finding(entity=f"{target} -> {ip}", ftype="DNS Resolution", source="MobileNetworkScanner", confidence="High", color="slate", category="Geo / Network OSINT", threat_level="Informational", status="Resolved", resolution=ip, tags=["dns", "resolution"]))

    findings.extend(await _check_mobile_operator(ip, client))

    mno_count = sum(1 for f in findings if "Mobile Network Operator" in f.type)
    mvno_count = sum(1 for f in findings if "MVNO" in f.type)
    backhaul_count = sum(1 for f in findings if "Mobile Backhaul" in f.type)

    findings.append(make_finding(entity=f"MNOs detected: {mno_count}", ftype="Mobile Operator Count", source="MobileNetworkScanner", confidence="Medium", color="purple", category="Geo / Network OSINT", tags=["mobile", "summary"]))
    findings.append(make_finding(entity=f"MVNOs detected: {mvno_count}", ftype="MVNO Count", source="MobileNetworkScanner", confidence="Medium", color="purple", category="Geo / Network OSINT", tags=["mobile", "summary"]))
    findings.append(make_finding(entity=f"Target: {target}", ftype="Mobile Scan Target", source="MobileNetworkScanner", confidence="High", color="slate", category="Geo / Network OSINT", tags=["mobile", "target"]))
    findings.append(make_finding(entity=f"Resolved IP: {ip}", ftype="Mobile Scan IP", source="MobileNetworkScanner", confidence="High", color="slate", category="Geo / Network OSINT", tags=["mobile", "ip"]))
    findings.append(make_finding(entity=f"Total mobile network findings: {len(findings)}", ftype="Mobile Scan Summary", source="MobileNetworkScanner", confidence="Medium", color="purple", category="Geo / Network OSINT", tags=["mobile", "summary"]))

    return findings
